from pptx import Presentation
from pptx.util import Pt, Emu
from pptx.dml.color import RGBColor

prs = Presentation(r'c:/Users/aluizio/Desktop/Aluizio/2026-04-ORION/Orion Test Systems Presentation .pptx')

print('=== SLIDE DIMENSIONS ===')
print(f'Width: {prs.slide_width.emu} emu = {prs.slide_width.inches:.2f} in')
print(f'Height: {prs.slide_height.emu} emu = {prs.slide_height.inches:.2f} in')
print(f'Total slides: {len(prs.slides)}')

print('\n=== SLIDE LAYOUTS ===')
for i, layout in enumerate(prs.slide_layouts):
    print(f'  Layout {i}: {layout.name}')

print('\n=== SLIDES CONTENT ===')
for i, slide in enumerate(prs.slides):
    print(f'\n--- Slide {i+1} (layout: {slide.slide_layout.name}) ---')
    for shape in slide.shapes:
        if shape.has_text_frame:
            txt = shape.text_frame.text.strip()
            if txt:
                print(f'  \"{txt[:100]}\"')
                # Get font info from first run of first paragraph
                try:
                    para = shape.text_frame.paragraphs[0]
                    if para.runs:
                        run = para.runs[0]
                        if run.font.color.rgb:
                            print(f'    color: #{run.font.color.rgb}')
                        if run.font.size:
                            print(f'    size: {run.font.size.pt}pt')
                        if run.font.name:
                            print(f'    font: {run.font.name}')
                except:
                    pass
        # Background fill
        try:
            fill = shape.fill
            if fill.type == 1:  # solid
                print(f'    shape fill: #{fill.fore_color.rgb}')
        except:
            pass

# Theme colors
print('\n=== THEME COLORS ===')
try:
    theme = prs.slide_master.theme_color_map
    print(theme)
except Exception as e:
    print(f'Theme map error: {e}')
"

