for (\$i = 1; \$i -le \$prs.SlideMaster.CustomLayouts.Count; \$i++) {
    Write-Host \$i ':' \$prs.SlideMaster.CustomLayouts.Item(\$i).Name
}

# Color scheme from theme
Write-Host '=== THEME COLORS ==='
for (\$i = 1; \$i -le 10; \$i++) {
    try {
        \$c = \$prs.SlideMaster.Theme.ThemeColorScheme.Colors(\$i).RGB
        Write-Host \"Color \$i : RGB\" (\$c -band 0xFF) ((\$c -shr 8) -band 0xFF) ((\$c -shr 16) -band 0xFF)
    } catch {}
}

# Slide titles
Write-Host '=== SLIDES ==='
for (\$i = 1; \$i -le \$prs.Slides.Count; \$i++) {
    \$slide = \$prs.Slides.Item(\$i)
    Write-Host \"Slide \$i (layout: \$(\$slide.Layout)):\"
    for (\$j = 1; \$j -le \$slide.Shapes.Count; \$j++) {
        \$shape = \$slide.Shapes.Item(\$j)
        if (\$shape.HasTextFrame) {
            \$txt = \$shape.TextFrame.TextRange.Text
            if (\$txt.Trim() -ne '') {
                Write-Host \"  [\$j] \$(\$txt.Substring(0, [Math]::Min(80, \$txt.Length)))\"
                Write-Host \"      Font: \$(\$shape.TextFrame.TextRange.Font.Name) Size:\$(\$shape.TextFrame.TextRange.Font.Size) Color:\$(\$shape.TextFrame.TextRange.Font.Color.RGB)\"
            }
        }
        # Shape fill
        try {
            if (\$shape.Fill.Type -eq 1) { # solid
                Write-Host \"  [\$j] fill RGB: \$(\$shape.Fill.ForeColor.RGB)\"
            }
        } catch {}
    }
}

\$prs.Close()
\$ppt.Quit()
